$(document).ready(function(){var t=$("#sidebar"),a=$("#sidebar-toggle, #sidebar-close"),o=$("#sidebar-mask"),s=$("body");$(a).on("click",function(e){e.preventDefault(),a.toggleClass("active"),t.toggleClass("active"),o.toggleClass("active"),s.toggleClass("overflow-hidden")}),$(document).on("click touchstart",function(e){0==$(e.target).closest(t).length&&0==$(e.target).closest(a).length&&(a.removeClass("active"),t.removeClass("active"),o.removeClass("active"),s.removeClass("overflow-hidden"))}),$(".card-toggle-btn").on("click",function(e){e.preventDefault(),$(this).toggleClass("active").parent().next(".card-body").slideToggle(300)})});